def validate_xml(file_path):
    import xml.etree.ElementTree as ET
    
    try:
        tree = ET.parse(file_path)
        root = tree.getroot()
        return True, root
    except ET.ParseError as e:
        return False, str(e)
    except FileNotFoundError:
        return False, "File not found"
    except Exception as e:
        return False, str(e)